def greet(name):
    return '你好，' + name

# 函数赋值给变量
say_hello = greet
print(say_hello('小明'))

# 函数作为参数
def call_func(func, arg):
    return func(arg)

print(call_func(greet, '小红'))

import time

def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print('{} 耗时: {:.4f}秒'.format(func.__name__, end - start))
        return result
    return wrapper

@timer
def slow_function():
    total = 0
    for i in range(1000000):
        total += i
    return total

result = slow_function()
print('结果:', result)

def repeat(times):
    def decorator(func):
        def wrapper(*args, **kwargs):
            for _ in range(times):
                result = func(*args, **kwargs)
            return result
        return wrapper
    return decorator

@repeat(3)
def say_hello(name):
    print('你好，{}!'.format(name))

say_hello('小明')

