exercises.solution:
def log(func):
    def wrapper(*args, **kwargs):
        print('调用函数: {}'.format(func.__name__))
        result = func(*args, **kwargs)
        print('函数 {} 返回: {}'.format(func.__name__, result))
        return result
    return wrapper

@log
def add(a, b):
    return a + b

add(3, 5)

