exercises.solution:
def cache(func):
    memo = {}
    def wrapper(*args):
        if args in memo:
            print('缓存命中: {}'.format(args))
            return memo[args]
        result = func(*args)
        memo[args] = result
        return result
    return wrapper

@cache
def square(n):
    print('计算中...')
    return n * n

print(square(4))
print(square(4))
